#!/usr/bin/env node
const os = require('os');
const process = require('process');

function main() {
  console.log('='.repeat(60));
  console.log('  Node.js Environment Diagnostics');
  console.log('='.repeat(60));
  console.log(`\nRuntime: ${process.version}`);
  console.log(`Path: ${process.execPath}`);
  console.log(`OS: ${os.type()} ${os.release()}`);
  console.log(`CPU Cores: ${os.cpus().length}`);
  ['PATH','HOME','USER'].forEach(k => {
    if (process.env[k]) console.log(`${k}=${process.env[k].substring(0,80)}...`);
  });
  console.log('\n' + '='.repeat(60));
}

main();
